1	use dioxus::prelude::*;
2	use crate::api;
3	use crate::auth::{AuthState, AUTH};
4	use crate::components::ToastManager;
5	
6	#[component]
7	pub fn Login() -> Element {
8	    let mut username = use_signal(String::new);
9	    let mut password = use_signal(String::new);
10	    let mut error = use_signal(|| None::<String>);
11	    let mut loading = use_signal(|| false);
12	    let mut api_status = use_signal(|| "Checking...".to_string());
13	
14	    use_effect(move || {
15	        spawn(async move {
16	            match api::check_health().await {
17	                Ok(h) => api_status.set(format!("Connected ({})", h.status)),
18	                Err(e) => api_status.set(format!("Offline: {}", e)),
19	            }
20	        });
21	    });
22	
23	    let handle_login = move |evt: Event<FormData>| {
24	        evt.prevent_default();
25	        spawn(async move {
26	            loading.set(true);
27	            error.set(None);
28	
29	            match api::login(&username.read(), &password.read()).await {
30	                Ok(resp) => {
31	                    api::set_token(&resp.data.token);
32	                    *AUTH.write() = AuthState::logged_in(resp.data.user);
33	                    // Hard redirect — forces full page reload so MainLayout
34	                    // sees the token in localStorage on fresh evaluation
35	                    if let Some(window) = web_sys::window() {
36	                        let _ = window.location().set_href("/dashboard");
37	                    }
38	                }
39	                Err(e) => {
40	                    error.set(Some(format!("Login failed: {}", e)));
41	                    loading.set(false);
42	                }
43	            }
44	        });
45	    };
46	
47	    rsx! {
48	        div { class: "login-page",
49	            div { class: "login-card",
50	                div { class: "login-header",
51	                    h1 { class: "login-title", "CampusLearn" }
52	                    p { class: "login-subtitle", "Operations Suite" }
53	                }
54	                form { class: "login-form", onsubmit: handle_login,
55	                    div { class: "form-group",
56	                        label { r#for: "username", "Username" }
57	                        input {
58	                            r#type: "text", id: "username", class: "form-input",
59	                            placeholder: "Enter your username", required: true,
60	                            value: "{username}", oninput: move |e| username.set(e.value()),
61	                        }
62	                    }
63	                    div { class: "form-group",
64	                        label { r#for: "password", "Password" }
65	                        input {
66	                            r#type: "password", id: "password", class: "form-input",
67	                            placeholder: "Enter your password", required: true,
68	                            value: "{password}", oninput: move |e| password.set(e.value()),
69	                        }
70	                    }
71	                    if let Some(err) = error.read().as_ref() {
72	                        div { class: "form-error", "{err}" }
73	                    }
74	                    button {
75	                        r#type: "submit", class: "btn btn-primary btn-full",
76	                        disabled: *loading.read(),
77	                        if *loading.read() { "Signing in..." } else { "Sign In" }
78	                    }
79	                }
80	                div { class: "login-footer",
81	                    span { class: "api-status", "API: {api_status}" }
82	                }
83	            }
84	        }
85	    }
86	}
