12	impl AuthState {
13	    pub fn logged_in(user: UserInfo) -> Self {
14	        Self { user: Some(user), is_authenticated: true, is_loading: false }
15	    }
16	
17	    pub fn logged_out() -> Self {
18	        Self { user: None, is_authenticated: false, is_loading: false }
19	    }
20	
21	    pub fn role(&self) -> &str {
22	        self.user.as_ref().map(|u| u.role.as_str()).unwrap_or("")
23	    }
24	
25	    pub fn is_admin(&self) -> bool {
26	        self.role() == "admin"
27	    }
28	
29	    pub fn is_staff_or_above(&self) -> bool {
30	        matches!(self.role(), "admin" | "staff_author")
31	    }
32	
33	    pub fn can_review(&self) -> bool {
34	        matches!(self.role(), "admin" | "dept_reviewer")
35	    }
36	}
37	
38	pub static AUTH: GlobalSignal<AuthState> = Signal::global(AuthState::default);
39	
40	pub fn logout() {
41	    api::clear_token();
42	    *AUTH.write() = AuthState::logged_out();
43	    // Full page reload to wipe all in-memory signals/cache
44	    if let Some(window) = web_sys::window() {
45	        let _ = window.location().set_href("/login");
46	    }
