1	use gloo_net::http::Request;
2	use gloo_storage::{LocalStorage, Storage};
3	use serde::de::DeserializeOwned;
4	
5	const STORAGE_TOKEN_KEY: &str = "campus_learn_token";
6	
7	fn api_base() -> String {
8	    // Use same origin — nginx proxies /api/ and /health to the backend
9	    web_sys::window()
10	        .and_then(|w| w.location().origin().ok())
11	        .unwrap_or_else(|| "http://localhost:3000".to_string())
12	}
13	
14	pub fn get_token() -> Option<String> {
15	    LocalStorage::get::<String>(STORAGE_TOKEN_KEY).ok()
16	}
17	
18	pub fn set_token(token: &str) {
19	    let _ = LocalStorage::set(STORAGE_TOKEN_KEY, token.to_string());
20	}
21	
22	pub fn clear_token() {
23	    LocalStorage::delete(STORAGE_TOKEN_KEY);
24	}
25	
26	pub fn is_logged_in() -> bool {
27	    get_token().is_some()
28	}
29	
30	async fn do_get<T: DeserializeOwned>(path: &str) -> Result<T, String> {
31	    let url = format!("{}{}", api_base(), path);
32	    let mut req = Request::get(&url);
33	    if let Some(token) = get_token() {
34	        req = req.header("Authorization", &format!("Bearer {}", token));
35	    }
36	    let resp = req.send().await.map_err(|e| e.to_string())?;
37	    if resp.ok() {
38	        resp.json::<T>().await.map_err(|e| e.to_string())
39	    } else {
40	        Err(format!("HTTP {}: {}", resp.status(), resp.status_text()))
41	    }
42	}
43	
44	async fn do_post<T: DeserializeOwned>(path: &str, body: &impl serde::Serialize) -> Result<T, String> {
45	    let url = format!("{}{}", api_base(), path);
46	    let mut req = Request::post(&url).header("Content-Type", "application/json");
47	    if let Some(token) = get_token() {
48	        req = req.header("Authorization", &format!("Bearer {}", token));
49	    }
50	    let resp = req.json(body).map_err(|e| e.to_string())?.send().await.map_err(|e| e.to_string())?;
51	    if resp.ok() {
52	        resp.json::<T>().await.map_err(|e| e.to_string())
53	    } else {
54	        Err(format!("HTTP {}: {}", resp.status(), resp.status_text()))
55	    }
56	}
