45	                delivered += 1;
46	            }
47	            Err(err) => {
48	                webhook_repo::mark_failed(pool, entry.id, None, Some(&err)).await?;
49	                failed += 1;
50	
51	                if entry.attempts + 1 >= entry.max_attempts {
