12	/// Guard that requires recent re-authentication (within configured window, default 15 min)
13	pub struct ReauthRequired {
14	    pub claims: crate::auth::jwt::Claims,
15	}
16	
17	#[rocket::async_trait]
18	impl<'r> FromRequest<'r> for ReauthRequired {
19	    type Error = Json<ApiError>;
20	
21	    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
22	        let user = match AuthenticatedUser::from_request(req).await {
23	            Outcome::Success(u) => u,
24	            Outcome::Error(e) => return Outcome::Error(e),
25	            Outcome::Forward(f) => return Outcome::Forward(f),
26	        };
27	
28	        let pool = req.rocket().state::<MySqlPool>().expect("DB pool not configured");
29	        let config = req.rocket().state::<AppConfig>().expect("AppConfig not configured");
30	
31	        let db_user = match user_repo::find_by_id(pool, user.claims.user_id).await {
32	            Ok(Some(u)) => u,
33	            _ => return Outcome::Error((
34	                Status::Unauthorized,
35	                Json(ApiError::unauthorized("User not found")),
36	            )),
37	        };
38	
39	        let reauth_ok = db_user.last_reauth_at.map(|ts| {
40	            let elapsed = Utc::now().naive_utc() - ts;
41	            elapsed.num_minutes() < config.reauth_window_minutes
42	        }).unwrap_or(false);
43	
44	        if !reauth_ok {
45	            return Outcome::Error((
46	                Status::Forbidden,
47	                Json(ApiError::new(Status::Forbidden, "Re-authentication required for this action. POST /api/v1/auth/reauth first.")),
48	            ));
49	        }
50	
51	        Outcome::Success(ReauthRequired { claims: user.claims })
52	    }
53	}
