1	use sqlx::MySqlPool;
2	use uuid::Uuid;
3	use chrono::NaiveDateTime;
4	
5	use crate::config::AppConfig;
6	use crate::dto::approval::*;
7	use crate::repositories::{approval_repo, course_repo, audit_repo, security_repo};
8	use crate::services::version_service;
9	use crate::utils::errors::AppError;
10	
11	pub async fn submit_for_approval(
12	    pool: &MySqlPool, config: &AppConfig, course_uuid: &str,
13	    req: &SubmitApprovalRequest, user_id: i64, correlation_id: Option<&str>,
14	) -> Result<String, AppError> {
15	    let course = course_repo::find_course_by_uuid(pool, course_uuid).await?
16	        .ok_or_else(|| AppError::NotFound("Course not found".to_string()))?;
17	
18	    // Only draft or rejected courses can be submitted
19	    if course.status != "draft" && course.status != "rejected" {
20	        return Err(AppError::Validation(format!(
21	            "Cannot submit course in '{}' status for approval", course.status
22	        )));
23	    }
24	
25	    // Check no active approval exists
26	    if let Some(_) = approval_repo::find_active_approval_for_course(pool, course.id).await? {
27	        return Err(AppError::Validation("An active approval request already exists for this course".to_string()));
28	    }
29	
30	    // Parse effective date (MM/DD/YYYY HH:MM AM/PM)
31	    let effective_dt = parse_effective_date(&req.effective_date)?;
32	    let effective_str = effective_dt.format("%Y-%m-%d %H:%M:%S").to_string();
33	
34	    // Create version snapshot
35	    let version_num = version_service::create_version_snapshot(
36	        pool, config, course.id, user_id, Some(&format!("Submitted for approval: {}", req.release_notes)),
37	    ).await?;
38	
39	    // Create approval request
40	    let approval_uuid = Uuid::new_v4().to_string();
41	    let approval_id = approval_repo::create_approval(
42	        pool, &approval_uuid, "course", course.id, user_id,
43	        &req.release_notes, &effective_str, version_num, req.notes.as_deref(),
44	    ).await?;
45	
46	    // Create two approval steps
47	    approval_repo::create_step(pool, &Uuid::new_v4().to_string(), approval_id as i64, 1, "dept_reviewer").await?;
48	    approval_repo::create_step(pool, &Uuid::new_v4().to_string(), approval_id as i64, 2, "admin").await?;
49	
50	    // Update course status
51	    course_repo::update_course_status(pool, course.id, "pending_approval").await?;
52	
53	    let _ = audit_repo::create_audit_log(
54	        pool, &Uuid::new_v4().to_string(), Some(user_id), "approval.submit",
55	        "course", Some(course.id), None,
56	        Some(&serde_json::json!({"release_notes": req.release_notes, "effective_date": req.effective_date, "version": version_num})),
57	        None, None, correlation_id,
58	    ).await;
59	
60	    Ok(approval_uuid)
61	}
62	
63	pub async fn review_approval(
64	    pool: &MySqlPool, config: &AppConfig, approval_uuid: &str,
65	    req: &ReviewApprovalRequest, reviewer_id: i64, reviewer_role: &str,
66	    correlation_id: Option<&str>,
67	) -> Result<(), AppError> {
68	    let approval = approval_repo::find_approval_by_uuid(pool, approval_uuid).await?
69	        .ok_or_else(|| AppError::NotFound("Approval request not found".to_string()))?;
70	
71	    // Self-approval prevention: reviewer cannot be the requester
72	    if approval.requested_by == reviewer_id {
73	        let _ = security_repo::create_security_event(
74	            pool, &Uuid::new_v4().to_string(), "self_approval_attempt", "warning",
75	            Some(reviewer_id), None,
76	            &format!("User {} attempted to approve their own request {}", reviewer_id, approval_uuid),
77	            None, correlation_id,
78	        ).await;
79	        return Err(AppError::Forbidden("You cannot approve your own submission".to_string()));
80	    }
81	
82	    // Get current pending step
83	    let step = approval_repo::get_current_pending_step(pool, approval.id).await?
84	        .ok_or_else(|| AppError::Validation("No pending approval step found".to_string()))?;
85	
86	    // Verify reviewer has appropriate role for this step
87	    if let Some(required_role) = &step.reviewer_role {
88	        if reviewer_role != required_role && reviewer_role != "admin" {
89	            return Err(AppError::Forbidden(format!(
90	                "This step requires a '{}' reviewer", required_role
91	            )));
92	        }
93	    }
94	
95	    let step_status = if req.approved { "approved" } else { "rejected" };
96	    approval_repo::update_step(pool, step.id, reviewer_id, step_status, req.comments.as_deref()).await?;
97	
98	    if req.approved {
99	        // Check if there's a next pending step
100	        let next_step = approval_repo::get_current_pending_step(pool, approval.id).await?;
101	        if next_step.is_some() {
102	            // Move to next step
103	            approval_repo::update_approval_status(pool, approval.id, "pending_step2").await?;
104	        } else {
105	            // All steps approved - determine if scheduled or immediate
106	            let now = chrono::Utc::now().naive_utc();
107	            let course = course_repo::find_course_by_id(pool, approval.entity_id).await?
108	                .ok_or_else(|| AppError::Internal("Course not found".to_string()))?;
109	
110	            if let Some(effective_date) = approval.effective_date {
111	                if effective_date > now {
112	                    // Schedule for future
113	                    approval_repo::update_approval_status(pool, approval.id, "approved_scheduled").await?;
114	                    course_repo::update_course_status(pool, approval.entity_id, "approved_scheduled").await?;
115	                    course_repo::update_course_version_info(
116	                        pool, approval.entity_id, approval.version_number.unwrap_or(1),
117	                        approval.release_notes.as_deref(),
118	                        Some(&effective_date.format("%Y-%m-%d %H:%M:%S").to_string()),
119	                    ).await?;
120	                    approval_repo::create_scheduled_transition(
121	                        pool, &Uuid::new_v4().to_string(), approval.entity_id, approval.id,
122	                        "published", &effective_date.format("%Y-%m-%d %H:%M:%S").to_string(),
123	                    ).await?;
124	                } else {
125	                    // Publish immediately
126	                    approval_repo::update_approval_status(pool, approval.id, "approved").await?;
127	                    course_repo::update_course_status(pool, approval.entity_id, "published").await?;
128	                    course_repo::update_course_version_info(
