17	pub async fn submit_for_approval(
18	    pool: &State<MySqlPool>,
19	    config: &State<AppConfig>,
20	    user: CourseAuthorGuard,
21	    course_uuid: String,
22	    body: Json<SubmitApprovalRequest>,
23	) -> Result<Json<ApiResponse<serde_json::Value>>, (Status, Json<ApiError>)> {
24	    if let Err(e) = body.validate() {
25	        let msg = e.field_errors().values()
26	            .flat_map(|errs| errs.iter().filter_map(|e| e.message.as_ref().map(|m| m.to_string())))
27	            .collect::<Vec<_>>().join("; ");
28	        return Err((Status::BadRequest, Json(ApiError::bad_request(msg))));
29	    }
30	
31	    let uuid = approval_service::submit_for_approval(
32	        pool.inner(), config.inner(), &course_uuid, &body, user.claims.user_id, &user.claims.role, None,
33	    ).await.map_err(|e| <(Status, Json<ApiError>)>::from(e))?;
34	
35	    Ok(ApiResponse::ok(serde_json::json!({"approval_uuid": uuid})))
36	}
