11	fn can_view_course(course: &Course, role: &str, user_id: i64, department_id: Option<i64>) -> bool {
12	    match role {
13	        "admin" => true,
14	        "staff_author" => course.created_by == Some(user_id) || course.status != "draft",
15	        "dept_reviewer" => {
16	            department_id.map_or(false, |d| course.department_id == Some(d))
17	                || course.status == "published"
18	        }
19	        _ => course.status == "published",
20	    }
21	}
22	
23	fn assert_course_owner(course: &Course, role: &str, user_id: i64) -> Result<(), AppError> {
24	    if role == "admin" || course.created_by == Some(user_id) {
25	        Ok(())
26	    } else {
27	        Err(AppError::Forbidden("You do not own this course".to_string()))
28	    }
29	}
