33	pub async fn create_course(
34	    pool: &MySqlPool, req: &CreateCourseRequest, user_id: i64, correlation_id: Option<&str>,
35	) -> Result<String, AppError> {
36	    let uuid = Uuid::new_v4().to_string();
37	    course_repo::create_course(
38	        pool, &uuid, &req.title, &req.code, req.description.as_deref(),
39	        req.department_id, req.term_id, user_id, req.max_enrollment,
40	    ).await.map_err(|e| {
41	        if e.to_string().contains("Duplicate") {
42	            AppError::Validation(format!("Course code '{}' already exists", req.code))
43	        } else {
44	            AppError::Database(e)
45	        }
46	    })?;
47	
48	    let course = course_repo::find_course_by_uuid(pool, &uuid).await?
49	        .ok_or_else(|| AppError::Internal("Failed to retrieve created course".to_string()))?;
50	
51	    if let Some(tag_ids) = &req.tag_ids {
52	        course_repo::set_course_tags(pool, course.id, tag_ids).await?;
53	    }
54	
55	    let _ = audit_repo::create_audit_log(
56	        pool, &Uuid::new_v4().to_string(), Some(user_id), "course.create",
57	        "course", Some(course.id), None,
58	        Some(&serde_json::json!({"title": req.title, "code": req.code})),
59	        None, None, correlation_id,
60	    ).await;
61	
62	    Ok(uuid)
63	}
