65	pub async fn get_course(
66	    pool: &MySqlPool, uuid: &str, role: &str, user_id: i64, department_id: Option<i64>,
67	) -> Result<CourseResponse, AppError> {
68	    let course = course_repo::find_course_by_uuid(pool, uuid).await?
69	        .ok_or_else(|| AppError::NotFound("Course not found".to_string()))?;
70	
71	    if !can_view_course(&course, role, user_id, department_id) {
72	        return Err(AppError::Forbidden("Access denied".to_string()));
