79	pub async fn list_courses(
80	    pool: &MySqlPool, role: &str, user_id: i64, department_id: Option<i64>,
81	) -> Result<Vec<CourseResponse>, AppError> {
82	    let courses = match role {
83	        "admin" => {
84	            sqlx::query_as::<_, crate::models::course::Course>(
85	                "SELECT * FROM courses ORDER BY updated_at DESC"
86	            ).fetch_all(pool).await?
87	        }
88	        "staff_author" => course_repo::list_courses_for_author(pool, user_id).await?,
89	        "dept_reviewer" => {
90	            if let Some(dept_id) = department_id {
91	                course_repo::list_courses_by_department(pool, dept_id).await?
