93	                vec![]
94	            }
95	        }
96	        "faculty" | "student" => course_repo::list_published_courses(pool).await?,
97	        _ => vec![],
98	    };
99	
100	    let mut responses = Vec::new();
101	    for course in courses {
102	        let tags = course_repo::get_course_tags(pool, course.id).await.unwrap_or_default();
103	        responses.push(build_course_response(course, tags));
104	    }
105	    Ok(responses)
106	}
