108	pub async fn update_course(
109	    pool: &MySqlPool, uuid: &str, req: &UpdateCourseRequest, user_id: i64, role: &str,
110	    correlation_id: Option<&str>,
111	) -> Result<(), AppError> {
112	    let course = course_repo::find_course_by_uuid(pool, uuid).await?
113	        .ok_or_else(|| AppError::NotFound("Course not found".to_string()))?;
114	
115	    let status = CourseStatus::from_str(&course.status);
116	    match status {
117	        Some(CourseStatus::Draft) | Some(CourseStatus::Rejected) => {}
118	        _ => return Err(AppError::Validation(format!(
119	            "Cannot edit course in '{}' status. Only draft or rejected courses can be edited.", course.status
120	        ))),
121	    }
122	
123	    assert_course_owner(&course, role, user_id)?;
124	
125	    let old_values = serde_json::json!({"title": course.title, "description": course.description});
126	
127	    course_repo::update_course(
128	        pool, course.id,
129	        req.title.as_deref(), req.description.as_deref(),
130	        req.department_id, req.term_id, req.max_enrollment,
131	    ).await?;
132	
133	    if let Some(tag_ids) = &req.tag_ids {
134	        course_repo::set_course_tags(pool, course.id, tag_ids).await?;
135	    }
136	
137	    let _ = audit_repo::create_audit_log(
138	        pool, &Uuid::new_v4().to_string(), Some(user_id), "course.update",
139	        "course", Some(course.id), Some(&old_values),
140	        Some(&serde_json::json!({"title": req.title, "description": req.description})),
141	        None, None, correlation_id,
142	    ).await;
143	
144	    Ok(())
145	}
