292	pub async fn register_media(pool: &MySqlPool, req: &CreateMediaRequest, user_id: i64) -> Result<MediaResponse, AppError> {
293	    if !ALLOWED_MEDIA_TYPES.contains(&req.mime_type.as_str()) {
294	        return Err(AppError::Validation(format!(
295	            "Invalid media type '{}'. Allowed: PDF, MP4, PNG", req.mime_type
296	        )));
297	    }
298	    if req.file_size_bytes > MAX_MEDIA_SIZE_BYTES {
299	        return Err(AppError::Validation(format!(
300	            "File size {} bytes exceeds maximum of 500 MB", req.file_size_bytes
301	        )));
302	    }
303	
304	    let uuid = Uuid::new_v4().to_string();
305	    let validated = true;
306	    course_repo::create_media(pool, &uuid, req.lesson_id, user_id,
307	        &req.file_name, &req.file_path, &req.mime_type, req.file_size_bytes,
308	        req.checksum.as_deref(), req.alt_text.as_deref(), validated, None).await?;
309	
310	    Ok(MediaResponse {
311	        uuid, file_name: req.file_name.clone(), file_path: req.file_path.clone(),
312	        mime_type: req.mime_type.clone(), file_size_bytes: req.file_size_bytes,
313	        status: "ready".to_string(), validated: true, validation_error: None,
314	    })
315	}
