161	pub async fn get_approval(
162	    pool: &MySqlPool, uuid: &str,
163	    role: &str, user_id: i64, department_id: Option<i64>,
164	) -> Result<ApprovalResponse, AppError> {
165	    let approval = approval_repo::find_approval_by_uuid(pool, uuid).await?
166	        .ok_or_else(|| AppError::NotFound("Approval request not found".to_string()))?;
167	
168	    let can_view = match role {
169	        "admin" => true,
170	        _ if approval.requested_by == user_id => true,
171	        "dept_reviewer" => {
172	            // Allow if the course belongs to the reviewer's department
173	            if let Some(dept_id) = department_id {
174	                let course = course_repo::find_course_by_id(pool, approval.entity_id).await?;
175	                course.map_or(false, |c| c.department_id == Some(dept_id))
176	            } else {
177	                false
178	            }
179	        }
180	        _ => false,
181	    };
182	    if !can_view {
183	        return Err(AppError::Forbidden("Access denied".to_string()));
184	    }
185	
186	    let steps = approval_repo::get_steps(pool, approval.id).await?;
187	    Ok(build_approval_response(approval, steps))
188	}
