190	pub async fn list_approval_queue(
191	    pool: &MySqlPool, role: &str, department_id: Option<i64>,
192	) -> Result<Vec<ApprovalQueueItem>, AppError> {
193	    let approvals = if role == "admin" {
194	        approval_repo::list_pending_approvals(pool).await?
195	    } else if let Some(dept_id) = department_id {
196	        approval_repo::list_pending_for_department(pool, dept_id).await?
197	    } else {
198	        vec![]
199	    };
200	
201	    let mut items = Vec::new();
202	    for approval in approvals {
203	        let steps = approval_repo::get_steps(pool, approval.id).await?;
204	        let course = course_repo::find_course_by_id(pool, approval.entity_id).await?;
205	        let requester = crate::repositories::user_repo::find_by_id(pool, approval.requested_by).await?;
206	
207	        items.push(ApprovalQueueItem {
208	            course_title: course.as_ref().map(|c| c.title.clone()).unwrap_or_default(),
209	            course_code: course.as_ref().map(|c| c.code.clone()).unwrap_or_default(),
210	            requester_name: requester.as_ref().map(|u| u.full_name.clone()).unwrap_or_default(),
211	            approval: build_approval_response(approval, steps),
212	        });
213	    }
214	    Ok(items)
215	}
