217	pub async fn process_scheduled_transitions(pool: &MySqlPool) -> Result<u32, AppError> {
218	    let transitions = approval_repo::list_pending_transitions(pool).await?;
219	    let mut count = 0;
220	    for t in transitions {
221	        course_repo::update_course_status(pool, t.course_id, &t.target_status).await?;
222	        approval_repo::mark_transition_executed(pool, t.id).await?;
223	
224	        let _ = audit_repo::create_audit_log(
225	            pool, &Uuid::new_v4().to_string(), None, "scheduled_transition.execute",
226	            "course", Some(t.course_id), None,
227	            Some(&serde_json::json!({"target_status": t.target_status, "scheduled_at": t.scheduled_at.to_string()})),
228	            None, None, None,
229	        ).await;
230	        count += 1;
231	    }
232	    Ok(count)
233	}
