235	fn parse_effective_date(s: &str) -> Result<NaiveDateTime, AppError> {
236	    // Try: MM/DD/YYYY HH:MM AM/PM
237	    chrono::NaiveDateTime::parse_from_str(s, "%m/%d/%Y %I:%M %p")
