239	        .or_else(|_| chrono::NaiveDateTime::parse_from_str(s, "%Y-%m-%d %H:%M:%S"))
240	        .map_err(|_| AppError::Validation(
241	            "Invalid effective date format. Use MM/DD/YYYY HH:MM AM/PM".to_string()
242	        ))
