7	pub async fn seed_default_users(pool: &MySqlPool) -> Result<(), Box<dyn std::error::Error>> {
8	    seed_departments(pool).await?;
9	    seed_permissions(pool).await?;
10	
11	    let count = user_repo::count_users(pool).await?;
12	    if count > 0 {
13	        tracing::info!("Users already exist, skipping user seed");
14	        return Ok(());
15	    }
16	
17	    tracing::info!("Seeding default accounts");
18	
19	    let accounts = [
20	        ("admin", "Admin@12345678", "admin@campuslearn.local", "System Administrator", "admin"),
21	        ("author", "Author@1234567", "author@campuslearn.local", "Default Author", "staff_author"),
22	        ("reviewer", "Review@1234567", "reviewer@campuslearn.local", "Default Reviewer", "dept_reviewer"),
23	        ("faculty", "Faculty@123456", "faculty@campuslearn.local", "Default Faculty", "faculty"),
24	        ("student", "Student@12345", "student@campuslearn.local", "Default Student", "student"),
25	    ];
26	
27	    for (username, password, email, full_name, role) in accounts {
28	        let pw_hash = hash_password(password)?;
29	        match user_repo::create_user(pool, &Uuid::new_v4().to_string(), username, &pw_hash, email, full_name, role).await {
30	            Ok(_) => tracing::info!(username = username, role = role, "Seeded user"),
31	            Err(e) => {
32	                tracing::error!(username = username, role = role, error = %e, "Failed to seed user");
33	                return Err(e.into());
34	            }
35	        }
36	    }
37	
38	    tracing::info!("Default accounts seeded successfully");
39	    Ok(())
40	}
