11	pub async fn submit_for_approval(
12	    pool: &MySqlPool, config: &AppConfig, course_uuid: &str,
13	    req: &SubmitApprovalRequest, user_id: i64, role: &str, correlation_id: Option<&str>,
14	) -> Result<String, AppError> {
15	    let course = course_repo::find_course_by_uuid(pool, course_uuid).await?
16	        .ok_or_else(|| AppError::NotFound("Course not found".to_string()))?;
17	
18	    // Only the course owner (or admin) may submit for approval
19	    if role != "admin" && course.created_by != Some(user_id) {
20	        return Err(AppError::Forbidden("You do not own this course".to_string()));
21	    }
22	
23	    // Only draft or rejected courses can be submitted
24	    if course.status != "draft" && course.status != "rejected" {
25	        return Err(AppError::Validation(format!(
26	            "Cannot submit course in '{}' status for approval", course.status
27	        )));
28	    }
29	
30	    // Check no active approval exists
31	    if let Some(_) = approval_repo::find_active_approval_for_course(pool, course.id).await? {
32	        return Err(AppError::Validation("An active approval request already exists for this course".to_string()));
33	    }
34	
35	    // Parse effective date (MM/DD/YYYY HH:MM AM/PM)
36	    let effective_dt = parse_effective_date(&req.effective_date)?;
37	    let effective_str = effective_dt.format("%Y-%m-%d %H:%M:%S").to_string();
38	
39	    // Create version snapshot
40	    let version_num = version_service::create_version_snapshot(
41	        pool, config, course.id, user_id, Some(&format!("Submitted for approval: {}", req.release_notes)),
42	    ).await?;
43	
44	    // Create approval request
45	    let approval_uuid = Uuid::new_v4().to_string();
46	    let approval_id = approval_repo::create_approval(
47	        pool, &approval_uuid, "course", course.id, user_id,
48	        &req.release_notes, &effective_str, version_num, req.notes.as_deref(),
49	    ).await?;
50	
51	    // Create two approval steps
52	    approval_repo::create_step(pool, &Uuid::new_v4().to_string(), approval_id as i64, 1, "dept_reviewer").await?;
53	    approval_repo::create_step(pool, &Uuid::new_v4().to_string(), approval_id as i64, 2, "admin").await?;
54	
55	    // Update course status
56	    course_repo::update_course_status(pool, course.id, "pending_approval").await?;
57	
58	    let _ = audit_repo::create_audit_log(
59	        pool, &Uuid::new_v4().to_string(), Some(user_id), "approval.submit",
60	        "course", Some(course.id), None,
61	        Some(&serde_json::json!({"release_notes": req.release_notes, "effective_date": req.effective_date, "version": version_num})),
