68	pub async fn review_approval(
69	    pool: &MySqlPool, config: &AppConfig, approval_uuid: &str,
70	    req: &ReviewApprovalRequest, reviewer_id: i64, reviewer_role: &str,
71	    correlation_id: Option<&str>,
72	) -> Result<(), AppError> {
73	    let approval = approval_repo::find_approval_by_uuid(pool, approval_uuid).await?
74	        .ok_or_else(|| AppError::NotFound("Approval request not found".to_string()))?;
75	
76	    // Self-approval prevention: reviewer cannot be the requester
77	    if approval.requested_by == reviewer_id {
78	        let _ = security_repo::create_security_event(
79	            pool, &Uuid::new_v4().to_string(), "self_approval_attempt", "warning",
80	            Some(reviewer_id), None,
81	            &format!("User {} attempted to approve their own request {}", reviewer_id, approval_uuid),
82	            None, correlation_id,
83	        ).await;
84	        return Err(AppError::Forbidden("You cannot approve your own submission".to_string()));
85	    }
86	
87	    // Get current pending step
88	    let step = approval_repo::get_current_pending_step(pool, approval.id).await?
89	        .ok_or_else(|| AppError::Validation("No pending approval step found".to_string()))?;
90	
91	    // Verify reviewer has appropriate role for this step
92	    if let Some(required_role) = &step.reviewer_role {
93	        if reviewer_role != required_role && reviewer_role != "admin" {
94	            return Err(AppError::Forbidden(format!(
95	                "This step requires a '{}' reviewer", required_role
96	            )));
97	        }
98	    }
99	
100	    let step_status = if req.approved { "approved" } else { "rejected" };
101	    approval_repo::update_step(pool, step.id, reviewer_id, step_status, req.comments.as_deref()).await?;
102	
103	    if req.approved {
104	        // Check if there's a next pending step
105	        let next_step = approval_repo::get_current_pending_step(pool, approval.id).await?;
106	        if next_step.is_some() {
107	            // Move to next step
108	            approval_repo::update_approval_status(pool, approval.id, "pending_step2").await?;
109	        } else {
110	            // All steps approved - determine if scheduled or immediate
111	            let now = chrono::Utc::now().naive_utc();
112	            let course = course_repo::find_course_by_id(pool, approval.entity_id).await?
113	                .ok_or_else(|| AppError::Internal("Course not found".to_string()))?;
114	
115	            if let Some(effective_date) = approval.effective_date {
116	                if effective_date > now {
117	                    // Schedule for future
118	                    approval_repo::update_approval_status(pool, approval.id, "approved_scheduled").await?;
119	                    course_repo::update_course_status(pool, approval.entity_id, "approved_scheduled").await?;
120	                    course_repo::update_course_version_info(
121	                        pool, approval.entity_id, approval.version_number.unwrap_or(1),
122	                        approval.release_notes.as_deref(),
123	                        Some(&effective_date.format("%Y-%m-%d %H:%M:%S").to_string()),
124	                    ).await?;
125	                    approval_repo::create_scheduled_transition(
126	                        pool, &Uuid::new_v4().to_string(), approval.entity_id, approval.id,
127	                        "published", &effective_date.format("%Y-%m-%d %H:%M:%S").to_string(),
128	                    ).await?;
129	                } else {
130	                    // Publish immediately
131	                    approval_repo::update_approval_status(pool, approval.id, "approved").await?;
132	                    course_repo::update_course_status(pool, approval.entity_id, "published").await?;
133	                    course_repo::update_course_version_info(
134	                        pool, approval.entity_id, approval.version_number.unwrap_or(1),
135	                        approval.release_notes.as_deref(), None,
136	                    ).await?;
137	                }
138	            } else {
139	                // No effective date means immediate
140	                approval_repo::update_approval_status(pool, approval.id, "approved").await?;
141	                course_repo::update_course_status(pool, approval.entity_id, "published").await?;
142	            }
143	        }
144	    } else {
145	        // Rejected
146	        approval_repo::update_approval_status(pool, approval.id, "rejected").await?;
147	        course_repo::update_course_status(pool, approval.entity_id, "rejected").await?;
148	    }
149	
150	    let _ = audit_repo::create_audit_log(
151	        pool, &Uuid::new_v4().to_string(), Some(reviewer_id),
152	        if req.approved { "approval.approve" } else { "approval.reject" },
153	        "approval", Some(approval.id), None,
154	        Some(&serde_json::json!({"step": step.step_order, "comments": req.comments})),
155	        None, None, correlation_id,
156	    ).await;
157	
158	    Ok(())
159	}
