162	    pool: &MySqlPool, uuid: &str,
163	    role: &str, user_id: i64, department_id: Option<i64>,
164	) -> Result<ApprovalResponse, AppError> {
165	    let approval = approval_repo::find_approval_by_uuid(pool, uuid).await?
166	        .ok_or_else(|| AppError::NotFound("Approval request not found".to_string()))?;
167	
168	    let active_term_id = term_repo::find_active_term(pool).await
169	        .map_err(AppError::Database)?
170	        .map(|t| t.id);
171	
172	    let can_view = match role {
173	        "admin" => true,
174	        _ if approval.requested_by == user_id => true,
175	        "dept_reviewer" => {
176	            // Allow if the course belongs to the reviewer's department AND active term
177	            if let Some(dept_id) = department_id {
178	                let course = course_repo::find_course_by_id(pool, approval.entity_id).await?;
179	                course.map_or(false, |c| {
180	                    c.department_id == Some(dept_id)
181	                        && term_matches(c.term_id, active_term_id)
182	                })
183	            } else {
184	                false
185	            }
186	        }
187	        _ => false,
188	    };
189	    if !can_view {
190	        return Err(AppError::Forbidden("Access denied".to_string()));
191	    }
192	
193	    let steps = approval_repo::get_steps(pool, approval.id).await?;
194	    Ok(build_approval_response(approval, steps))
195	}
