126	        .ok_or_else(|| AppError::NotFound("Approval request not found".to_string()))?;
127	
128	    // Self-approval prevention: reviewer cannot be the requester
129	    if approval.requested_by == reviewer_id {
130	        let _ = security_repo::create_security_event(
131	            pool, &Uuid::new_v4().to_string(), "self_approval_attempt", "warning",
132	            Some(reviewer_id), None,
133	            &format!("User {} attempted to approve their own request {}", reviewer_id, approval_uuid),
134	            None, correlation_id,
135	        ).await;
136	        return Err(AppError::Forbidden("You cannot approve your own submission".to_string()));
137	    }
138	
139	    // Get current pending step
140	    let step = approval_repo::get_current_pending_step(pool, approval.id).await?
141	        .ok_or_else(|| AppError::Validation("No pending approval step found".to_string()))?;
142	
143	    // Verify reviewer has appropriate role for this step
144	    if let Some(required_role) = &step.reviewer_role {
145	        if reviewer_role != required_role && reviewer_role != "admin" {
146	            return Err(AppError::Forbidden(format!(
147	                "This step requires a '{}' reviewer", required_role
148	            )));
149	        }
150	    }
151	
152	    let step_status = if req.approved { "approved" } else { "rejected" };
153	    approval_repo::update_step(pool, step.id, reviewer_id, step_status, req.comments.as_deref()).await?;
154	
155	    if req.approved {
156	        // Check if there's a next pending step
157	        let next_step = approval_repo::get_current_pending_step(pool, approval.id).await?;
158	        if next_step.is_some() {
159	            // Move to next step
160	            approval_repo::update_approval_status(pool, approval.id, "pending_step2").await?;
161	        } else {
162	            // All steps approved - determine if scheduled or immediate
163	            let is_unpublish = approval.entity_type == "course_unpublish";
164	            let target_status = if is_unpublish { "unpublished" } else { "published" };
165	            let now = chrono::Utc::now().naive_utc();
166	            let _course = course_repo::find_course_by_id(pool, approval.entity_id).await?
167	                .ok_or_else(|| AppError::Internal("Course not found".to_string()))?;
168	
169	            if let Some(effective_date) = approval.effective_date {
170	                if effective_date > now {
171	                    // Approved with future effective date — create scheduled transition
172	                    approval_repo::update_approval_status(pool, approval.id, "approved_scheduled").await?;
173	                    if !is_unpublish {
174	                        // Publish: move course to approved_scheduled and record version info
175	                        course_repo::update_course_status(pool, approval.entity_id, "approved_scheduled").await?;
176	                        course_repo::update_course_version_info(
177	                            pool, approval.entity_id, approval.version_number.unwrap_or(1),
178	                            approval.release_notes.as_deref(),
179	                            Some(&effective_date.format("%Y-%m-%d %H:%M:%S").to_string()),
180	                        ).await?;
181	                    }
182	                    // For unpublish: course stays pending_unpublish until ScheduledTransition fires
183	                    approval_repo::create_scheduled_transition(
184	                        pool, &Uuid::new_v4().to_string(), approval.entity_id, approval.id,
185	                        target_status, &effective_date.format("%Y-%m-%d %H:%M:%S").to_string(),
186	                    ).await?;
187	                } else {
188	                    // Effective date is in the past — execute immediately
189	                    approval_repo::update_approval_status(pool, approval.id, "approved").await?;
190	                    course_repo::update_course_status(pool, approval.entity_id, target_status).await?;
191	                    if !is_unpublish {
192	                        course_repo::update_course_version_info(
193	                            pool, approval.entity_id, approval.version_number.unwrap_or(1),
194	                            approval.release_notes.as_deref(), None,
195	                        ).await?;
196	                    }
197	                }
198	            } else {
199	                // No effective date — execute immediately
200	                approval_repo::update_approval_status(pool, approval.id, "approved").await?;
201	                course_repo::update_course_status(pool, approval.entity_id, target_status).await?;
202	                if !is_unpublish {
203	                    course_repo::update_course_version_info(
204	                        pool, approval.entity_id, approval.version_number.unwrap_or(1),
205	                        approval.release_notes.as_deref(), None,
206	                    ).await?;
207	                }
208	            }
209	        }
210	    } else {
211	        // Rejected: for unpublish restore to published, for publish set rejected
212	        let restore_status = if approval.entity_type == "course_unpublish" { "published" } else { "rejected" };
213	        approval_repo::update_approval_status(pool, approval.id, "rejected").await?;
214	        course_repo::update_course_status(pool, approval.entity_id, restore_status).await?;
