21	pub async fn check_availability(pool: &MySqlPool, resource_uuid: &str, date: &str) -> Result<Vec<AvailabilitySlot>, AppError> {
22	    let resource = booking_repo::find_resource_by_uuid(pool, resource_uuid).await?
23	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
24	
25	    let start_str = format!("{} {}", date, resource.open_time.format("%H:%M:%S"));
26	    let close_str = format!("{} {}", date, resource.close_time.format("%H:%M:%S"));
27	
28	    let existing = booking_repo::find_conflicts(pool, resource.id, &start_str, &close_str).await?;
29	    let blackouts = booking_repo::list_blackouts(pool, resource.id).await?;
30	
31	    // Generate hourly slots
32	    let mut slots = Vec::new();
33	    let open_hour = resource.open_time.hour() as i64;
34	    let close_hour = resource.close_time.hour() as i64;
35	
36	    for hour in open_hour..close_hour {
37	        let slot_start = format!("{} {:02}:00:00", date, hour);
38	        let slot_end = format!("{} {:02}:00:00", date, hour + 1);
39	
40	        let conflict = existing.iter().any(|b| {
41	            let bs = b.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
42	            let be = b.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
43	            bs < slot_end && be > slot_start
44	        });
45	
46	        let blackout = blackouts.iter().any(|bl| {
47	            let bs = bl.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
48	            let be = bl.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
49	            bs < slot_end && be > slot_start
50	        });
51	
52	        let (available, reason) = if blackout {
53	            (false, Some("Maintenance blackout".to_string()))
54	        } else if conflict {
55	            (false, Some("Already booked".to_string()))
56	        } else {
57	            (true, None)
58	        };
59	
60	        slots.push(AvailabilitySlot {
61	            start: slot_start, end: slot_end, available, conflict_reason: reason,
62	        });
63	    }
64	    Ok(slots)
65	}
