67	pub async fn create_booking(
68	    pool: &MySqlPool, req: &CreateBookingRequest, user_id: i64, correlation_id: Option<&str>,
69	) -> Result<BookingResponse, AppError> {
70	    let resource = booking_repo::find_resource_by_uuid(pool, &req.resource_uuid).await?
71	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
72	
73	    // Check user doesn't have active booking restriction
74	    if booking_repo::has_active_restriction(pool, user_id, "booking_suspended").await? {
75	        return Err(AppError::Forbidden("You have an active booking restriction due to policy breaches".to_string()));
76	    }
77	
78	    // Parse times
79	    let start_dt = parse_datetime(&req.start_time)?;
80	    let end_dt = parse_datetime(&req.end_time)?;
81	    let now = Utc::now().naive_utc();
82	
83	    // Validate: end > start
84	    if end_dt <= start_dt {
85	        return Err(AppError::Validation("End time must be after start time".to_string()));
86	    }
87	
88	    // Validate: max 90 days ahead
89	    let max_future = now + Duration::days(MAX_ADVANCE_DAYS);
90	    if start_dt > max_future {
91	        return Err(AppError::Validation(format!("Cannot book more than {} days in advance", MAX_ADVANCE_DAYS)));
92	    }
93	
94	    // Validate: within operating hours
95	    let start_time_only = start_dt.time();
96	    let end_time_only = end_dt.time();
97	    if start_time_only < resource.open_time || end_time_only > resource.close_time {
98	        return Err(AppError::Validation(format!(
99	            "Booking must be within resource hours: {} - {}",
100	            resource.open_time.format("%H:%M"), resource.close_time.format("%H:%M")
101	        )));
102	    }
103	
104	    // Validate: max duration for room type
105	    let duration_hours = (end_dt - start_dt).num_hours();
106	    if duration_hours > resource.max_booking_hours as i64 {
107	        return Err(AppError::Validation(format!(
108	            "Maximum booking duration for this resource is {} hours", resource.max_booking_hours
109	        )));
110	    }
111	
112	    // Validate: max 2 active reservations per user per resource
113	    let active_count = booking_repo::count_active_bookings_for_resource(pool, user_id, resource.id).await?;
114	    if active_count >= MAX_ACTIVE_PER_RESOURCE as i64 {
115	        return Err(AppError::Validation(format!(
116	            "Maximum {} active reservations per resource", MAX_ACTIVE_PER_RESOURCE
117	        )));
118	    }
119	
120	    let uuid = Uuid::new_v4().to_string();
121	    let start_str = start_dt.format("%Y-%m-%d %H:%M:%S").to_string();
122	    let end_str = end_dt.format("%Y-%m-%d %H:%M:%S").to_string();
123	
124	    // Atomic booking with conflict prevention
125	    booking_repo::create_booking_atomic(
126	        pool, &uuid, resource.id, user_id, &req.title,
127	        req.description.as_deref(), &start_str, &end_str,
