156	pub async fn reschedule_booking(
157	    pool: &MySqlPool, booking_uuid: &str, req: &RescheduleRequest, user_id: i64,
158	) -> Result<(), AppError> {
159	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
160	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
161	
162	    if booking.booked_by != user_id {
163	        return Err(AppError::Forbidden("You can only reschedule your own bookings".to_string()));
164	    }
165	
166	    if booking.reschedule_count >= MAX_RESCHEDULES {
167	        return Err(AppError::Validation(format!("Maximum {} reschedules allowed", MAX_RESCHEDULES)));
168	    }
169	
170	    if booking.status != "confirmed" {
171	        return Err(AppError::Validation("Only confirmed bookings can be rescheduled".to_string()));
172	    }
173	
174	    let new_start = parse_datetime(&req.new_start_time)?;
175	    let new_end = parse_datetime(&req.new_end_time)?;
176	
177	    if new_end <= new_start {
178	        return Err(AppError::Validation("End time must be after start time".to_string()));
179	    }
180	
181	    let resource = booking_repo::find_resource_by_id(pool, booking.resource_id).await?
182	        .ok_or_else(|| AppError::Internal("Resource not found".to_string()))?;
183	
184	    // Check operating hours
185	    if new_start.time() < resource.open_time || new_end.time() > resource.close_time {
186	        return Err(AppError::Validation("New time must be within resource operating hours".to_string()));
187	    }
188	
189	    // Check duration
190	    let duration = (new_end - new_start).num_hours();
191	    if duration > resource.max_booking_hours as i64 {
192	        return Err(AppError::Validation(format!("Max {} hours", resource.max_booking_hours)));
193	    }
194	
195	    let new_start_str = new_start.format("%Y-%m-%d %H:%M:%S").to_string();
196	    let new_end_str = new_end.format("%Y-%m-%d %H:%M:%S").to_string();
197	
198	    // Check conflicts (exclude current booking)
199	    let conflicts = booking_repo::find_conflicts(pool, booking.resource_id, &new_start_str, &new_end_str).await?;
200	    let real_conflicts: Vec<_> = conflicts.into_iter().filter(|b| b.id != booking.id).collect();
201	    if !real_conflicts.is_empty() {
202	        return Err(AppError::Validation("New time conflicts with existing booking".to_string()));
203	    }
204	
205	    let orig_start = booking.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
206	    let orig_end = booking.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
207	
208	    booking_repo::create_reschedule_record(
209	        pool, &Uuid::new_v4().to_string(), booking.id, booking.reschedule_count + 1,
210	        user_id, &orig_start, &orig_end, &new_start_str, &new_end_str, req.reason.as_deref(),
211	    ).await?;
212	
213	    booking_repo::update_booking_times(pool, booking.id, &new_start_str, &new_end_str).await?;
214	    booking_repo::increment_reschedule_count(pool, booking.id).await?;
215	
216	    Ok(())
217	}
