219	pub async fn cancel_booking(
220	    pool: &MySqlPool, booking_uuid: &str, user_id: i64, role: &str, correlation_id: Option<&str>,
221	) -> Result<(), AppError> {
222	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
223	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
224	
225	    if booking.booked_by != user_id && role != "admin" {
226	        return Err(AppError::Forbidden("Not your booking".to_string()));
227	    }
228	
229	    if booking.status == "cancelled" {
230	        return Err(AppError::Validation("Booking already cancelled".to_string()));
231	    }
232	
233	    booking_repo::update_booking_status(pool, booking.id, "cancelled").await?;
234	
235	    // Late cancellation check: within 2 hours of start creates a breach
236	    let now = Utc::now().naive_utc();
237	    let hours_until_start = (booking.start_time - now).num_hours();
238	
239	    if hours_until_start < LATE_CANCEL_HOURS && booking.start_time > now {
240	        let breach_uuid = Uuid::new_v4().to_string();
241	        booking_repo::create_breach(
242	            pool, &breach_uuid, booking.booked_by, Some(booking.id),
243	            "late_cancellation", "medium",
244	            &format!("Booking cancelled within {} hours of start time", LATE_CANCEL_HOURS),
245	        ).await?;
246	
247	        // Check if user hit breach threshold -> auto-restrict
248	        let breach_count = booking_repo::count_recent_breaches(pool, booking.booked_by, BREACH_WINDOW_DAYS).await?;
249	        if breach_count >= BREACH_THRESHOLD {
250	            let already_restricted = booking_repo::has_active_restriction(pool, booking.booked_by, "booking_suspended").await?;
251	            if !already_restricted {
252	                let expires = (Utc::now() + Duration::days(30)).format("%Y-%m-%d %H:%M:%S").to_string();
253	                booking_repo::create_restriction(
254	                    pool, &Uuid::new_v4().to_string(), booking.booked_by,
255	                    "booking_suspended",
256	                    &format!("{} breaches in {} days triggered automatic booking suspension", breach_count, BREACH_WINDOW_DAYS),
257	                    user_id, &Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
258	                    Some(&expires), breach_count as i32, true,
259	                ).await?;
260	
261	                let _ = security_repo::create_security_event(
262	                    pool, &Uuid::new_v4().to_string(), "booking_auto_restriction", "warning",
263	                    Some(booking.booked_by), None,
264	                    &format!("Auto-restricted: {} breaches in {} days", breach_count, BREACH_WINDOW_DAYS),
265	                    None, correlation_id,
266	                ).await;
267	            }
268	        }
269	    }
270	
271	    let _ = audit_repo::create_audit_log(
272	        pool, &Uuid::new_v4().to_string(), Some(user_id), "booking.cancel",
273	        "booking", Some(booking.id), None,
274	        Some(&serde_json::json!({"hours_until_start": hours_until_start})),
275	        None, None, correlation_id,
276	    ).await;
277	
278	    Ok(())
279	}
