64	            "blacklisted_employer" => evaluate_blacklisted_employers(pool, rule).await?,
65	            "abnormal_compensation" => evaluate_abnormal_compensation(pool, rule).await?,
66	            "duplicate_posting" => evaluate_duplicate_postings(pool, rule).await?,
