79	async fn evaluate_posting_frequency(pool: &MySqlPool, rule: &crate::models::risk::RiskRule) -> Result<u32, AppError> {
80	    let conditions = &rule.conditions;
81	    let max_postings = conditions.get("max_postings").and_then(|v| v.as_i64()).unwrap_or(20);
82	    let window_hours = conditions.get("window_hours").and_then(|v| v.as_i64()).unwrap_or(24);
83	
84	    // Find employers with high posting frequency
85	    let rows: Vec<(String, i64)> = sqlx::query_as(
86	        "SELECT employer_name, COUNT(*) as cnt FROM employer_postings WHERE created_at > DATE_SUB(NOW(), INTERVAL ? HOUR) GROUP BY employer_name HAVING cnt > ?"
87	    ).bind(window_hours).bind(max_postings).fetch_all(pool).await?;
88	
89	    let mut count = 0;
90	    for (employer_name, cnt) in rows {
91	        risk_repo::create_risk_event(
92	            pool, &Uuid::new_v4().to_string(), rule.id, None,
93	            Some("employer_posting"), None, (cnt as f64 / max_postings as f64) * 100.0,
94	            Some(&serde_json::json!({"employer": employer_name, "posting_count": cnt, "window_hours": window_hours})),
95	        ).await?;
96	        count += 1;
97	    }
98	    Ok(count)
99	}
