101	async fn evaluate_blacklisted_employers(pool: &MySqlPool, rule: &crate::models::risk::RiskRule) -> Result<u32, AppError> {
102	    let rows: Vec<(i64, String, String, i64)> = sqlx::query_as(
103	        "SELECT ep.id, ep.employer_name, ep.title, ep.posted_by FROM employer_postings ep INNER JOIN blacklisted_employers be ON ep.employer_name = be.employer_name AND be.is_active = true WHERE ep.flagged = false AND ep.created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)"
104	    ).fetch_all(pool).await?;
105	
106	    let mut count = 0;
107	    for (posting_id, employer, title, posted_by) in rows {
108	        risk_repo::create_risk_event(
109	            pool, &Uuid::new_v4().to_string(), rule.id, Some(posted_by),
110	            Some("employer_posting"), Some(posting_id), 100.0,
111	            Some(&serde_json::json!({"employer": employer, "title": title})),
112	        ).await?;
113	
114	        // Flag the posting
115	        sqlx::query("UPDATE employer_postings SET flagged = true WHERE id = ?")
116	            .bind(posting_id).execute(pool).await?;
117	
118	        let _ = security_repo::create_security_event(
119	            pool, &Uuid::new_v4().to_string(), "blacklisted_employer_posting", "critical",
120	            Some(posted_by), None, &format!("Posting by blacklisted employer: {}", employer),
121	            None, None,
122	        ).await;
123	
124	        count += 1;
125	    }
126	    Ok(count)
127	}
