29	fn App() -> Element {
30	    // Hydrate auth state from localStorage token on app startup.
31	    // After a hard redirect (login → /dashboard), the page reloads and
32	    // the AUTH signal is empty. This fetches /auth/me to restore it.
33	    use_effect(move || {
34	        if api::is_logged_in() && !auth::AUTH.read().is_authenticated {
35	            spawn(async move {
36	                match api::get_me().await {
37	                    Ok(resp) => {
38	                        *auth::AUTH.write() = auth::AuthState::logged_in(resp.data);
39	                    }
40	                    Err(_) => {
41	                        // Token invalid or expired — clear it and reset signal
42	                        api::clear_token();
43	                        *auth::AUTH.write() = auth::AuthState::logged_out();
44	                    }
45	                }
46	            });
47	        }
48	    });
49	
50	    rsx! {
51	        components::ToastContainer {}
52	        Router::<Route> {}
53	    }
