1	#[macro_use] extern crate rocket;
2	
3	mod auth;
4	mod config;
5	mod dto;
6	mod jobs;
7	mod middleware;
8	mod models;
9	mod repositories;
10	mod routes;
11	mod services;
12	mod utils;
13	
14	use config::AppConfig;
15	use middleware::correlation::CorrelationId;
16	use rocket::fairing::AdHoc;
17	use sqlx::mysql::MySqlPoolOptions;
18	use tracing_subscriber::{fmt, EnvFilter};
19	
20	#[rocket::main]
21	async fn main() -> Result<(), Box<dyn std::error::Error>> {
22	    fmt()
23	        .with_env_filter(
24	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")),
25	        )
26	        .json()
27	        .init();
28	
29	    tracing::info!("Starting CampusLearn Operations Suite backend");
30	
31	    let config = AppConfig::from_env();
32	
33	    let pool = MySqlPoolOptions::new()
34	        .max_connections(config.db_max_connections)
35	        .connect(&config.database_url)
36	        .await?;
37	
38	    tracing::info!("Database connection pool established");
39	
40	    sqlx::migrate!("./migrations").run(&pool).await?;
41	    tracing::info!("Database migrations applied");
42	
43	    services::seed::seed_default_users(&pool).await?;
44	    services::seed::seed_resources_and_rules(&pool).await?;
45	
46	    // Background jobs: scheduled transitions, risk evaluation, webhooks (every 60s)
47	    let pool_jobs = pool.clone();
48	    tokio::spawn(async move {
49	        let mut interval = tokio::time::interval(std::time::Duration::from_secs(60));
50	        loop {
51	            interval.tick().await;
52	            let _ = jobs::run_scheduled_transitions(&pool_jobs).await;
53	            let _ = jobs::run_risk_evaluation(&pool_jobs).await;
54	            let _ = jobs::process_webhooks(&pool_jobs).await;
55	        }
56	    });
