103	    let rows: Vec<(i64, String, String, i64)> = sqlx::query_as(
104	        "SELECT ep.id, ep.employer_name, ep.title, ep.posted_by FROM employer_postings ep INNER JOIN blacklisted_employers be ON ep.employer_name = be.employer_name AND be.is_active = true WHERE ep.flagged = false AND ep.created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)"
105	    ).fetch_all(pool).await?;
106	
107	    let mut count = 0;
108	    for (posting_id, employer, title, posted_by) in rows {
109	        risk_repo::create_risk_event(
110	            pool, &Uuid::new_v4().to_string(), rule.id, Some(posted_by),
111	            Some("employer_posting"), Some(posting_id), 100.0,
112	            Some(&serde_json::json!({"employer": employer, "title": title})),
113	        ).await?;
114	
115	        // Flag the posting
116	        sqlx::query("UPDATE employer_postings SET flagged = true WHERE id = ?")
117	            .bind(posting_id).execute(pool).await?;
118	
119	        let _ = security_repo::create_security_event(
120	            pool, &Uuid::new_v4().to_string(), "blacklisted_employer_posting", "critical",
121	            Some(posted_by), None, &format!("Posting by blacklisted employer: {}", employer),
122	            None, None,
123	        ).await;
124	
125	        count += 1;
126	    }
127	    Ok(count)
128	}
