3	#[derive(Debug, Clone, PartialEq)]
4	pub enum ToastLevel { Success, Error, Warning, Info }
5	
6	#[derive(Debug, Clone)]
7	pub struct ToastMessage {
8	    pub id: u32,
9	    pub level: ToastLevel,
10	    pub text: String,
11	}
12	
13	pub static TOASTS: GlobalSignal<Vec<ToastMessage>> = Signal::global(Vec::new);
14	static TOAST_ID: GlobalSignal<u32> = Signal::global(|| 0);
15	
16	pub struct ToastManager;
17	
18	impl ToastManager {
19	    pub fn show(level: ToastLevel, text: impl Into<String>) {
20	        let mut counter = TOAST_ID.write();
21	        *counter += 1;
22	        let id = *counter;
23	        TOASTS.write().push(ToastMessage { id, level, text: text.into() });
24	        spawn(async move {
25	            gloo_timers::future::TimeoutFuture::new(4000).await;
26	            TOASTS.write().retain(|t| t.id != id);
27	        });
28	    }
29	    pub fn success(text: impl Into<String>) { Self::show(ToastLevel::Success, text); }
30	    pub fn error(text: impl Into<String>) { Self::show(ToastLevel::Error, text); }
31	}
32	
33	#[component]
34	pub fn ToastContainer() -> Element {
35	    let toasts = TOASTS.read();
36	    rsx! {
37	        div { class: "toast-container",
38	            for toast in toasts.iter() {
39	                div {
40	                    key: "{toast.id}",
41	                    class: match toast.level {
42	                        ToastLevel::Success => "toast toast-success",
43	                        ToastLevel::Error => "toast toast-error",
44	                        ToastLevel::Warning => "toast toast-warning",
45	                        ToastLevel::Info => "toast toast-info",
46	                    },
47	                    span { class: "toast-text", "{toast.text}" }
48	                    button {
49	                        class: "toast-close",
50	                        onclick: { let id = toast.id; move |_| { TOASTS.write().retain(|t| t.id != id); } },
51	                        "×"
52	                    }
53	                }
54	            }
55	        }
56	    }
57	}
