8	    if key_bytes.len() != 32 {
9	        return Err("Key must be 32 bytes (64 hex chars)".to_string());
10	    }
11	
12	    let key = Key::<Aes256Gcm>::from_slice(&key_bytes);
13	    let cipher = Aes256Gcm::new(key);
13	
14	    let mut nonce_bytes = [0u8; 12];
15	    rand::thread_rng().fill_bytes(&mut nonce_bytes);
16	    let nonce = Nonce::from_slice(&nonce_bytes);
17	
18	    let ciphertext = cipher.encrypt(nonce, plaintext.as_bytes())
19	        .map_err(|e| format!("Encryption failed: {}", e))?;
20	
21	    Ok((BASE64.encode(&ciphertext), hex::encode(nonce_bytes)))
22	}
23	
24	pub fn decrypt(ciphertext_b64: &str, iv_hex: &str, key_hex: &str) -> Result<String, String> {
25	    let key_bytes = hex::decode(key_hex).map_err(|e| format!("Invalid key hex: {}", e))?;
26	    let key = Key::<Aes256Gcm>::from_slice(&key_bytes);
27	    let cipher = Aes256Gcm::new(key);
28	
29	    let nonce_bytes = hex::decode(iv_hex).map_err(|e| format!("Invalid IV hex: {}", e))?;
30	    let nonce = Nonce::from_slice(&nonce_bytes);
31	
32	    let ciphertext = BASE64.decode(ciphertext_b64).map_err(|e| format!("Invalid base64: {}", e))?;
33	
34	    let plaintext = cipher.decrypt(nonce, ciphertext.as_ref())
35	        .map_err(|e| format!("Decryption failed: {}", e))?;
36	
37	    String::from_utf8(plaintext).map_err(|e| format!("Invalid UTF-8: {}", e))
38	}
