1	use aes_gcm::{Aes256Gcm, Key, Nonce};
2	use aes_gcm::aead::{Aead, KeyInit};
3	use base64::{Engine as _, engine::general_purpose::STANDARD as BASE64};
4	use rand::RngCore;
5	
6	pub fn encrypt(plaintext: &str, key_hex: &str) -> Result<(String, String), String> {
7	    let key_bytes = hex::decode(key_hex).map_err(|e| format!("Invalid key hex: {}", e))?;
8	    if key_bytes.len() != 32 {
9	        return Err("Key must be 32 bytes (64 hex chars)".to_string());
10	    }
11	
12	    let key = Key::<Aes256Gcm>::from_slice(&key_bytes);
13	    let cipher = Aes256Gcm::new(key);
14	
15	    let mut nonce_bytes = [0u8; 12];
16	    rand::thread_rng().fill_bytes(&mut nonce_bytes);
17	    let nonce = Nonce::from_slice(&nonce_bytes);
18	
19	    let ciphertext = cipher.encrypt(nonce, plaintext.as_bytes())
20	        .map_err(|e| format!("Encryption failed: {}", e))?;
21	
22	    Ok((BASE64.encode(&ciphertext), hex::encode(nonce_bytes)))
23	}
24	
25	pub fn decrypt(ciphertext_b64: &str, iv_hex: &str, key_hex: &str) -> Result<String, String> {
26	    let key_bytes = hex::decode(key_hex).map_err(|e| format!("Invalid key hex: {}", e))?;
27	    let key = Key::<Aes256Gcm>::from_slice(&key_bytes);
28	    let cipher = Aes256Gcm::new(key);
29	
30	    let nonce_bytes = hex::decode(iv_hex).map_err(|e| format!("Invalid IV hex: {}", e))?;
31	    let nonce = Nonce::from_slice(&nonce_bytes);
32	
33	    let ciphertext = BASE64.decode(ciphertext_b64).map_err(|e| format!("Invalid base64: {}", e))?;
34	
35	    let plaintext = cipher.decrypt(nonce, ciphertext.as_ref())
36	        .map_err(|e| format!("Decryption failed: {}", e))?;
37	
38	    String::from_utf8(plaintext).map_err(|e| format!("Invalid UTF-8: {}", e))
39	}
