68	pub async fn list_requests(pool: &MySqlPool, status: Option<&str>) -> Result<Vec<DataRequestResponse>, AppError> {
69	    let requests = privacy_repo::list_data_requests(pool, status).await?;
70	    Ok(requests.into_iter().map(|r| DataRequestResponse {
71	        uuid: r.uuid, user_id: r.user_id, request_type: r.request_type,
72	        status: r.status, reason: r.reason, admin_notes: r.admin_notes,
73	        result_file_path: r.result_file_path,
74	        created_at: r.created_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
75	        updated_at: r.updated_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
76	    }).collect())
77	}
