83	        status: r.status, reason: r.reason, admin_notes: r.admin_notes,
84	        result_file_path: r.result_file_path,
85	        created_at: r.created_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
86	        updated_at: r.updated_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
87	    }).collect())
88	}
