90	pub async fn store_sensitive_field(pool: &MySqlPool, user_id: i64, field_name: &str, value: &str, encryption_key: &str) -> Result<(), AppError> {
91	    let (encrypted, iv) = crypto_service::encrypt(value, encryption_key)
92	        .map_err(|e| AppError::Internal(format!("Encryption failed: {}", e)))?;
93	    privacy_repo::store_encrypted(pool, &Uuid::new_v4().to_string(), user_id, field_name, &encrypted, &iv).await?;
94	    Ok(())
