97	pub async fn get_masked_fields(pool: &MySqlPool, user_id: i64) -> Result<Vec<MaskedFieldResponse>, AppError> {
98	    let fields = privacy_repo::list_encrypted_fields(pool, user_id).await?;
99	    Ok(fields.into_iter().map(|f| MaskedFieldResponse {
100	        field_name: f.field_name.clone(),
101	        masked_value: mask_value(&f.field_name, &f.encrypted_value),
102	    }).collect())
103	}
