105	fn mask_value(field_name: &str, _encrypted: &str) -> String {
106	    match field_name {
107	        "ssn" => "***-**-####".to_string(),
108	        "bank_account" => "****####".to_string(),
109	        "bank_routing" => "****####".to_string(),
110	        _ => "********".to_string(),
111	    }
112	}
