8	pub async fn enqueue_event_webhooks(pool: &MySqlPool, event_type: &str, payload: &serde_json::Value) -> Result<u32, AppError> {
9	    let subscribers = risk_repo::get_subscribers_for_event(pool, event_type).await?;
