13	        if sub.channel != "webhook" {
14	            continue;
15	        }
16	        // For webhook channel, we'd need target_url stored somewhere.
17	        // For now, use a default on-prem endpoint pattern
18	        let target_url = format!("http://localhost:9090/webhooks/{}", event_type);
19	        let payload_str = serde_json::to_string(payload).unwrap_or_default();
20	        let signature = hmac_util::compute_signature("webhook-signing-secret", &payload_str);
21	
22	        webhook_repo::enqueue_webhook(
23	            pool, &Uuid::new_v4().to_string(), sub.id, event_type,
24	            payload, &target_url, Some(&signature),
25	        ).await?;
26	        count += 1;
27	    }
28	    Ok(count)
