31	/// Process pending webhooks - retry with backoff
32	pub async fn process_webhook_queue(pool: &MySqlPool) -> Result<(u32, u32), AppError> {
33	    let pending = webhook_repo::get_pending_webhooks(pool, 50).await?;
34	    let mut delivered = 0u32;
35	    let mut failed = 0u32;
36	
37	    for entry in pending {
38	        // Attempt delivery (simplified - in production would use HTTP client)
39	        // Since we're on-prem only, check if target is reachable
40	        let result = attempt_delivery(&entry.target_url, &entry.payload, entry.signature.as_deref()).await;
41	
42	        match result {
43	            Ok(code) => {
44	                webhook_repo::mark_delivered(pool, entry.id, code).await?;
45	                delivered += 1;
46	            }
47	            Err(err) => {
48	                webhook_repo::mark_failed(pool, entry.id, None, Some(&err)).await?;
49	                failed += 1;
50	
51	                if entry.attempts + 1 >= entry.max_attempts {
52	                    let _ = security_repo::create_security_event(
53	                        pool, &Uuid::new_v4().to_string(), "webhook_delivery_failed", "warning",
54	                        None, None, &format!("Webhook dead-lettered after {} attempts: {}", entry.max_attempts, entry.target_url),
55	                        Some(&serde_json::json!({"webhook_id": entry.id, "event_type": entry.event_type})), None,
56	                    ).await;
57	                }
58	            }
59	        }
60	    }
61	
62	    Ok((delivered, failed))
63	}
