65	async fn attempt_delivery(url: &str, payload: &serde_json::Value, signature: Option<&str>) -> Result<i32, String> {
66	    let client = reqwest::Client::builder()
67	        .timeout(std::time::Duration::from_secs(10))
68	        .build()
69	        .map_err(|e| e.to_string())?;
70	
71	    let mut builder = client.post(url)
72	        .header("Content-Type", "application/json")
73	        .json(payload);
74	
75	    if let Some(sig) = signature {
76	        builder = builder.header("X-Webhook-Signature", sig);
77	    }
78	
79	    match builder.send().await {
80	        Ok(resp) => Ok(resp.status().as_u16() as i32),
81	        Err(e) => Err(e.to_string()),
82	    }
83	}
