80	async fn evaluate_posting_frequency(pool: &MySqlPool, rule: &crate::models::risk::RiskRule) -> Result<u32, AppError> {
81	    let conditions = &rule.conditions;
82	    let max_postings = conditions.get("max_postings").and_then(|v| v.as_i64()).unwrap_or(20);
83	    let window_hours = conditions.get("window_hours").and_then(|v| v.as_i64()).unwrap_or(24);
84	
85	    // Find employers with high posting frequency
86	    let rows: Vec<(String, i64)> = sqlx::query_as(
87	        "SELECT employer_name, COUNT(*) as cnt FROM employer_postings WHERE created_at > DATE_SUB(NOW(), INTERVAL ? HOUR) GROUP BY employer_name HAVING cnt > ?"
88	    ).bind(window_hours).bind(max_postings).fetch_all(pool).await?;
89	
90	    let mut count = 0;
91	    for (employer_name, cnt) in rows {
92	        risk_repo::create_risk_event(
93	            pool, &Uuid::new_v4().to_string(), rule.id, None,
94	            Some("employer_posting"), None, (cnt as f64 / max_postings as f64) * 100.0,
95	            Some(&serde_json::json!({"employer": employer_name, "posting_count": cnt, "window_hours": window_hours})),
96	        ).await?;
97	        let _ = notification_service::notify_role(
98	            pool, "admin",
99	            "Risk Alert: Abnormal Posting Frequency",
100	            &format!("Employer '{}' posted {} times in {}h.", employer_name, cnt, window_hours),
101	            "risk", Some("employer_posting"), None,
102	        ).await;
103	        count += 1;
104	    }
105	    Ok(count)
106	}
