143	async fn evaluate_abnormal_compensation(pool: &MySqlPool, rule: &crate::models::risk::RiskRule) -> Result<u32, AppError> {
144	    let conditions = &rule.conditions;
145	    let min_amount = conditions.get("min_amount").and_then(|v| v.as_f64()).unwrap_or(500.0);
146	    let max_amount = conditions.get("max_amount").and_then(|v| v.as_f64()).unwrap_or(15000.0);
147	
148	    let rows: Vec<(i64, String, String, f64, i64)> = sqlx::query_as(
149	        "SELECT id, employer_name, title, compensation, posted_by FROM employer_postings WHERE posting_type = 'adjunct' AND compensation IS NOT NULL AND (compensation < ? OR compensation > ?) AND flagged = false AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)"
150	    ).bind(min_amount).bind(max_amount).fetch_all(pool).await?;
151	
152	    let mut count = 0;
153	    for (id, employer, title, comp, posted_by) in rows {
154	        let score = if comp < min_amount { 80.0 } else { 90.0 };
155	        risk_repo::create_risk_event(
156	            pool, &Uuid::new_v4().to_string(), rule.id, Some(posted_by),
157	            Some("employer_posting"), Some(id), score,
158	            Some(&serde_json::json!({"employer": employer, "title": title, "compensation": comp, "range": format!("{}-{}", min_amount, max_amount)})),
159	        ).await?;
160	        sqlx::query("UPDATE employer_postings SET flagged = true WHERE id = ?").bind(id).execute(pool).await?;
161	        count += 1;
162	    }
163	    Ok(count)
164	}
