6	/// Process scheduled course transitions (approved_scheduled -> published)
7	pub async fn run_scheduled_transitions(pool: &MySqlPool) -> Result<u32, Box<dyn std::error::Error>> {
8	    let count = approval_service::process_scheduled_transitions(pool).await?;
9	    if count > 0 {
10	        tracing::info!(count = count, "Processed scheduled transitions");
11	    }
12	    Ok(count)
13	}
14	
15	/// Run risk rule evaluation (default every 15 minutes)
16	pub async fn run_risk_evaluation(pool: &MySqlPool) -> Result<u32, Box<dyn std::error::Error>> {
17	    let count = risk_service::run_risk_evaluation(pool).await?;
18	    if count > 0 {
19	        tracing::info!(count = count, "Risk evaluation created new events");
20	    }
21	    Ok(count)
22	}
23	
24	/// Process pending webhook deliveries with retry/backoff
25	pub async fn process_webhooks(pool: &MySqlPool) -> Result<(u32, u32), Box<dyn std::error::Error>> {
26	    let (delivered, failed) = webhook_service::process_webhook_queue(pool).await?;
27	    if delivered > 0 || failed > 0 {
28	        tracing::info!(delivered = delivered, failed = failed, "Webhook processing completed");
29	    }
30	    Ok((delivered, failed))
31	}
32	
33	/// Clean up expired rate limit entries, nonces, and expired version snapshots
34	pub async fn cleanup_expired_data(pool: &MySqlPool) -> Result<(), Box<dyn std::error::Error>> {
35	    let cleaned = rate_limit_repo::cleanup_old_entries(pool).await?;
36	    if cleaned > 0 {
37	        tracing::debug!(cleaned = cleaned, "Cleaned up expired rate limit entries");
38	    }
39	
40	    sqlx::query("DELETE FROM used_nonces WHERE expires_at < NOW()")
41	        .execute(pool).await?;
42	
43	    // Clean expired course versions (180-day retention)
44	    sqlx::query("DELETE FROM course_versions WHERE expires_at IS NOT NULL AND expires_at < NOW()")
45	        .execute(pool).await?;
46	
47	    Ok(())
48	}
