19	/// Create booking using SELECT FOR UPDATE to prevent double-booking under concurrency.
20	/// Returns Ok(last_insert_id) or Err if conflict detected within the transaction.
21	pub async fn create_booking_atomic(
22	    pool: &MySqlPool, uuid: &str, resource_id: i64, booked_by: i64,
23	    title: &str, description: Option<&str>, start_time: &str, end_time: &str,
24	) -> Result<u64, sqlx::Error> {
25	    let mut tx = pool.begin().await?;
26	
27	    // Lock the resource row to serialize booking insertions for this resource
28	    sqlx::query("SELECT id FROM resources WHERE id = ? FOR UPDATE")
29	        .bind(resource_id).execute(&mut *tx).await?;
30	
31	    // Check for overlapping confirmed/pending bookings
32	    let conflict: Option<(i64,)> = sqlx::query_as(
33	        "SELECT id FROM bookings WHERE resource_id = ? AND status IN ('confirmed', 'pending') AND start_time < ? AND end_time > ? LIMIT 1"
34	    ).bind(resource_id).bind(end_time).bind(start_time)
35	    .fetch_optional(&mut *tx).await?;
36	
37	    if conflict.is_some() {
38	        tx.rollback().await?;
39	        return Err(sqlx::Error::Protocol("BOOKING_CONFLICT: Time slot already booked".to_string()));
40	    }
41	
42	    // Check for maintenance blackout overlap
43	    let blackout: Option<(i64,)> = sqlx::query_as(
44	        "SELECT id FROM resource_blackouts WHERE resource_id = ? AND start_time < ? AND end_time > ? LIMIT 1"
45	    ).bind(resource_id).bind(end_time).bind(start_time)
46	    .fetch_optional(&mut *tx).await?;
47	
48	    if blackout.is_some() {
49	        tx.rollback().await?;
50	        return Err(sqlx::Error::Protocol("BLACKOUT_CONFLICT: Resource under maintenance during requested time".to_string()));
51	    }
52	
53	    let r = sqlx::query(
54	        "INSERT INTO bookings (uuid, resource_id, booked_by, title, description, start_time, end_time, status) VALUES (?, ?, ?, ?, ?, ?, ?, 'confirmed')"
55	    ).bind(uuid).bind(resource_id).bind(booked_by).bind(title).bind(description)
56	    .bind(start_time).bind(end_time)
57	    .execute(&mut *tx).await?;
58	
59	    tx.commit().await?;
60	    Ok(r.last_insert_id())
61	}
