pub async fn reschedule_booking_atomic(
    pool: &MySqlPool,
    booking_id: i64,
    resource_id: i64,
    reschedule_uuid: &str,
    reschedule_number: i32,
    requested_by: i64,
    orig_start: &str,
    orig_end: &str,
    new_start: &str,
    new_end: &str,
    reason: Option<&str>,
) -> Result<(), sqlx::Error> {
    let mut tx = pool.begin().await?;

    // Lock resource row — serializes concurrent reschedule + create operations
